INSERT INTO products (name, price, stock, description, created_at, updated_at) VALUES
                                                                                   ('코튼 트윌 볼캡', 5000, 200, '데일리 필수템 코튼 트윌 볼캡. 가볍고 편안한 착용감으로 어떤 코디에도 포인트.', NOW(), NOW()),
                                                                                   ('베이직 스트라이프 삭스 3팩', 6900, 300, '데일리 필수 스트라이프 양말 3켤레 세트. 코튼 혼방으로 부드럽고 통기성 우수.', NOW(), NOW()),
                                                                                   ('오버핏 코튼 크루넥 티셔츠', 39000, 120, '부드러운 코튼 소재의 오버핏 크루넥 티셔츠. 데일리로 입기 좋은 베이직 아이템.', NOW(), NOW()),
                                                                                   ('워시드 와이드 데님 팬츠', 68000, 45, '빈티지 워싱 처리된 와이드 핏 데님. 편안한 핏감과 트렌디한 실루엣.', NOW(), NOW()),
                                                                                   ('캔버스 미니 에코백', 8900, 150, '가벼운 캔버스 소재의 미니 에코백. 간단한 외출과 서브백으로 활용도 만점.', NOW(), NOW()),
                                                                                   ('램스울 오버사이즈 니트', 89000, 30, '부드러운 램스울 혼방 니트. 여유로운 오버사이즈 핏으로 레이어드에 최적.', NOW(), NOW()),
                                                                                   ('나일론 카고 조거팬츠', 58000, 60, '경량 나일론 소재의 카고 조거팬츠. 스트릿 무드의 실용적인 디자인.', NOW(), NOW()),
                                                                                   ('레더 미니멀 크로스백', 128000, 20, '소프트 레더 소재의 미니멀 크로스백. 깔끔한 디자인으로 다양한 코디에 매치.', NOW(), NOW()),
                                                                                   ('청키 러닝 스니커즈', 159000, 25, '볼드한 청키 솔의 러닝 스니커즈. 뛰어난 쿠셔닝과 스타일리시한 디자인.', NOW(), NOW()),
                                                                                   ('울 블렌드 싱글 코트', 198000, 0, '고급 울 블렌드 소재의 싱글 코트. 클래식한 실루엣으로 격식있는 룩 완성.', NOW(), NOW()),
                                                                                   ('스트레치 슬림 치노팬츠', 48000, 80, '스트레치 소재로 편안한 슬림 치노팬츠. 오피스부터 캐주얼까지 활용도 높은 아이템.', NOW(), NOW()),
                                                                                   ('코튼 와플 반팔티', 9900, 180, '와플 조직의 코튼 반팔티. 은은한 텍스처감으로 심플하지만 디테일이 살아있는 아이템.', NOW(), NOW());